import { toArray } from '../../../../utils/zcutils';
import { SelectionToDomain } from './selection-to-domain';

/**
 *
 * @type {{LEGEND: getDomainTypes.LEGEND, PLOT: (function(*=): {}), SCROLL: (function(*=, *=): {x: {domain: Scroll, index: number}})}}
 */
const getDomainTypes = {
    /**
     *
     * @param selection
     * @param brushScale
     * @return {{x: {domain: *[], index: number}}}
     */
    SCROLL: function(selection, brushScale) {
        let brush = this,
            chart = brush.chart,
            dataType = chart.dataset.getDataType('x', 0),
            rotated = chart.axes.rotated,
            domain = SelectionToDomain(selection, brushScale, 'x', dataType, rotated);

        return { x: { domain, index: 0, dataType: dataType } };
    }
};

/**
 *
 * @return {*}
 * @constructor
 */
export function BrushDomain() {
    let args = toArray(arguments),
        type = args.shift();

    return getDomainTypes[type].apply(this, args);
}
